import statistics
import time
from dataclasses import dataclass, field
from typing import Callable

@dataclass
class StageBudget:
    name: str
    p50_ms: float
    p95_ms: float
    p99_ms: float

@dataclass
class PipelineBudget:
    stages: list[StageBudget] = field(default_factory=list)

    def total(self, percentile: str) -> float:
        return sum(getattr(s, percentile) for s in self.stages)

    def report(self) -> str:
        lines = ["Stage Latency Budget", "-" * 40]
        for s in self.stages:
            lines.append(f"{s.name:20s}  P50={s.p50_ms:6.0f}ms  P95={s.p95_ms:6.0f}ms  P99={s.p99_ms:6.0f}ms")
        lines.append("-" * 40)
        lines.append(f"{'TOTAL':20s}  P50={self.total('p50_ms'):6.0f}ms  P95={self.total('p95_ms'):6.0f}ms  P99={self.total('p99_ms'):6.0f}ms")
        return "
".join(lines)


# NFR definition for a two-turn agentic pipeline
budget = PipelineBudget(stages=[
    StageBudget("input_parsing",   p50_ms=20,   p95_ms=50,   p99_ms=80),
    StageBudget("retrieval_rag",   p50_ms=150,  p95_ms=350,  p99_ms=500),
    StageBudget("llm_inference",   p50_ms=1200, p95_ms=2500, p99_ms=4000),
    StageBudget("tool_dispatch",   p50_ms=300,  p95_ms=600,  p99_ms=800),
    StageBudget("output_format",   p50_ms=30,   p95_ms=60,   p99_ms=90),
])
print(budget.report())


# Stage timer context manager for runtime measurement
class StageTimer:
    def __init__(self, name: str, budget: StageBudget):
        self.name = name
        self.budget = budget
        self.elapsed_ms: float = 0.0

    def __enter__(self):
        self._start = time.perf_counter()
        return self

    def __exit__(self, *_):
        self.elapsed_ms = (time.perf_counter() - self._start) * 1000
        if self.elapsed_ms > self.budget.p99_ms:
            print(f"SLO BREACH [{self.name}]: {self.elapsed_ms:.1f}ms > P99 {self.budget.p99_ms}ms")
        elif self.elapsed_ms > self.budget.p95_ms:
            print(f"SLO WARNING [{self.name}]: {self.elapsed_ms:.1f}ms > P95 {self.budget.p95_ms}ms")


# Token budget tracker
class TokenBudgetTracker:
    def __init__(self, daily_limit: int, per_request_limit: int):
        self.daily_limit = daily_limit
        self.per_request_limit = per_request_limit
        self._daily_used = 0

    def check_and_record(self, prompt_tokens: int, completion_tokens: int) -> None:
        total = prompt_tokens + completion_tokens
        if total > self.per_request_limit:
            raise ValueError(f"Request tokens {total} exceed per-request limit {self.per_request_limit}")
        if self._daily_used + total > self.daily_limit:
            raise ValueError(f"Daily token quota exhausted: {self._daily_used}/{self.daily_limit}")
        self._daily_used += total
        pct = self._daily_used / self.daily_limit * 100
        if pct >= 80:
            print(f"ALERT: daily token usage at {pct:.1f}% ({self._daily_used}/{self.daily_limit})")

    @property
    def remaining(self) -> int:
        return self.daily_limit - self._daily_used


# Percentile computation from a sample of latency measurements
def compute_percentiles(latencies_ms: list[float]) -> dict:
    s = sorted(latencies_ms)
    n = len(s)
    return {
        "p50": s[int(n * 0.50)],
        "p95": s[int(n * 0.95)],
        "p99": s[int(n * 0.99)],
        "mean": statistics.mean(s),
        "max": s[-1],
    }
